INSERT INTO public."UsefulPage" (id, slug, "titleRu", "titleUz", "titleEn", "cardTextRu", "cardTextUz", "cardTextEn", "shortTitleRu", "shortTitleUz", "shortTitleEn", "shortTextRu", "shortTextUz", "shortTextEn", "fullTitleRu", "fullTitleUz", "fullTitleEn", "createdAt", "updatedAt") VALUES ('cmrq0ao3g0074wrk13y390m3e', 'what-is-imrad', 'Что такое стандарт IMRAD', 'IMRAD standarti nima', 'What is the IMRAD standard', 'IMRAD — это классическая структура научной статьи: Introduction, Methods, Results, Discussion — то есть Введение, Методы, Результаты, Обсуждение.', 'IMRAD — ilmiy maqolaning klassik tuzilmasi: Introduction, Methods, Results, Discussion — ya’ni Kirish, Metodlar, Natijalar, Muhokama.', 'IMRAD is the classic structure of a scientific article: Introduction, Methods, Results, Discussion.', NULL, NULL, NULL, 'IMRAD — это классическая структура научной статьи: Introduction, Methods, Results, Discussion — то есть Введение, Методы, Результаты, Обсуждение.', 'IMRAD — ilmiy maqolaning klassik tuzilmasi: Introduction, Methods, Results, Discussion — ya’ni Kirish, Metodlar, Natijalar, Muhokama.', 'IMRAD is the classic structure of a scientific article: Introduction, Methods, Results, Discussion.', NULL, NULL, NULL, '2026-07-18 06:49:11.548', '2026-07-18 06:49:11.548');
INSERT INTO public."UsefulPage" (id, slug, "titleRu", "titleUz", "titleEn", "cardTextRu", "cardTextUz", "cardTextEn", "shortTitleRu", "shortTitleUz", "shortTitleEn", "shortTextRu", "shortTextUz", "shortTextEn", "fullTitleRu", "fullTitleUz", "fullTitleEn", "createdAt", "updatedAt") VALUES ('cmrq0anyh001dwrk1t9li47qr', 'what-is-orcid', 'Что такое ORCID', 'ORCID nima', 'What is ORCID', 'ORCID — это персональный идентификатор исследователя. Он нужен для того, чтобы точно отличать одного автора от другого и связывать его с публикациями, аффилиациями, грантами и другими научными результатами.', 'ORCID — tadqiqotchining shaxsiy identifikatori. U bir muallifni boshqasidan aniq ajratish va uni maqolalari, affiliasiyasi, grantlari hamda boshqa ilmiy natijalari bilan bog‘lash uchun kerak.', 'ORCID is a personal researcher identifier. It is used to distinguish one author from another and connect the author with publications, affiliations, grants, and other research outputs.', NULL, NULL, NULL, 'ORCID — это персональный идентификатор исследователя. Он нужен для того, чтобы точно отличать одного автора от другого и связывать его с публикациями, аффилиациями, грантами и другими научными результатами.', 'ORCID — tadqiqotchining shaxsiy identifikatori. U bir muallifni boshqasidan aniq ajratish va uni maqolalari, affiliasiyasi, grantlari hamda boshqa ilmiy natijalari bilan bog‘lash uchun kerak.', 'ORCID is a personal researcher identifier. It is used to distinguish one author from another and connect the author with publications, affiliations, grants, and other research outputs.', NULL, NULL, NULL, '2026-07-18 06:49:11.369', '2026-07-18 06:49:11.369');
INSERT INTO public."UsefulPage" (id, slug, "titleRu", "titleUz", "titleEn", "cardTextRu", "cardTextUz", "cardTextEn", "shortTitleRu", "shortTitleUz", "shortTitleEn", "shortTextRu", "shortTextUz", "shortTextEn", "fullTitleRu", "fullTitleUz", "fullTitleEn", "createdAt", "updatedAt") VALUES ('cmrq0anyv001kwrk1njd2wo0y', 'what-is-a-doi', 'Что такое DOI', 'DOI nima', 'What is DOI', 'DOI — это постоянный цифровой идентификатор статьи, книги, главы, датасета или другого научного материала. Он нужен для точного поиска, проверки и цитирования публикации.', 'DOI — maqola, kitob, bo‘lim, dataset yoki boshqa ilmiy materialning doimiy raqamli identifikatori. U nashrni aniq topish, tekshirish va iqtibos qilish uchun kerak.', 'DOI is a persistent digital identifier for an article, book, chapter, dataset, or other scholarly material. It is used for accurate discovery, verification, and citation.', NULL, NULL, NULL, 'DOI — это постоянный цифровой идентификатор статьи, книги, главы, датасета или другого научного материала. Он нужен для точного поиска, проверки и цитирования публикации.', 'DOI — maqola, kitob, bo‘lim, dataset yoki boshqa ilmiy materialning doimiy raqamli identifikatori. U nashrni aniq topish, tekshirish va iqtibos qilish uchun kerak.', 'DOI is a persistent digital identifier for an article, book, chapter, dataset, or other scholarly material. It is used for accurate discovery, verification, and citation.', NULL, NULL, NULL, '2026-07-18 06:49:11.383', '2026-07-18 06:49:11.383');
INSERT INTO public."UsefulPage" (id, slug, "titleRu", "titleUz", "titleEn", "cardTextRu", "cardTextUz", "cardTextEn", "shortTitleRu", "shortTitleUz", "shortTitleEn", "shortTextRu", "shortTextUz", "shortTextEn", "fullTitleRu", "fullTitleUz", "fullTitleEn", "createdAt", "updatedAt") VALUES ('cmrq0anz2001swrk1ijyhvkzj', 'what-is-scopus', 'Что такое Scopus', 'Scopus nima', 'What is Scopus', 'Scopus — это международная база научной литературы, которая индексирует журналы, статьи, книги, конференции и отслеживает цитирования, авторов и источники.', 'Scopus — jurnallar, maqolalar, kitoblar, konferensiyalarni indekslaydigan hamda iqtiboslar, mualliflar va manbalarni kuzatadigan xalqaro ilmiy adabiyotlar bazasidir.', 'Scopus is an international scholarly literature database that indexes journals, articles, books, conference materials, and tracks citations, authors, and sources.', NULL, NULL, NULL, 'Scopus — это международная база научной литературы, которая индексирует журналы, статьи, книги, конференции и отслеживает цитирования, авторов и источники.', 'Scopus — jurnallar, maqolalar, kitoblar, konferensiyalarni indekslaydigan hamda iqtiboslar, mualliflar va manbalarni kuzatadigan xalqaro ilmiy adabiyotlar bazasidir.', 'Scopus is an international scholarly literature database that indexes journals, articles, books, conference materials, and tracks citations, authors, and sources.', NULL, NULL, NULL, '2026-07-18 06:49:11.39', '2026-07-18 06:49:11.39');
INSERT INTO public."UsefulPage" (id, slug, "titleRu", "titleUz", "titleEn", "cardTextRu", "cardTextUz", "cardTextEn", "shortTitleRu", "shortTitleUz", "shortTitleEn", "shortTextRu", "shortTextUz", "shortTextEn", "fullTitleRu", "fullTitleUz", "fullTitleEn", "createdAt", "updatedAt") VALUES ('cmrq0anzf001zwrk1lvakvk1y', 'what-is-journal-quartile', 'Что такое квартиль журнала', 'Jurnal kvartili nima', 'What is a journal quartile', 'Квартиль показывает, какое место журнал занимает среди других журналов своей научной категории. Q1 — верхние 25%, Q2 — следующие 25%, Q3 — ниже среднего, Q4 — нижние 25%.', 'Kvartil jurnalning o‘z ilmiy kategoriyasidagi boshqa jurnallar orasida qaysi o‘rinni egallashini ko‘rsatadi. Q1 — yuqori 25%, Q2 — keyingi 25%, Q3 — o‘rtachadan past, Q4 — quyi 25%.', 'A quartile shows a journal’s position among other journals in its subject category. Q1 is the top 25%, Q2 the next 25%, Q3 below average, and Q4 the bottom 25%.', NULL, NULL, NULL, 'Квартиль показывает, какое место журнал занимает среди других журналов своей научной категории. Q1 — верхние 25%, Q2 — следующие 25%, Q3 — ниже среднего, Q4 — нижние 25%.', 'Kvartil jurnalning o‘z ilmiy kategoriyasidagi boshqa jurnallar orasida qaysi o‘rinni egallashini ko‘rsatadi. Q1 — yuqori 25%, Q2 — keyingi 25%, Q3 — o‘rtachadan past, Q4 — quyi 25%.', 'A quartile shows a journal’s position among other journals in its subject category. Q1 is the top 25%, Q2 the next 25%, Q3 below average, and Q4 the bottom 25%.', NULL, NULL, NULL, '2026-07-18 06:49:11.403', '2026-07-18 06:49:11.403');
INSERT INTO public."UsefulPage" (id, slug, "titleRu", "titleUz", "titleEn", "cardTextRu", "cardTextUz", "cardTextEn", "shortTitleRu", "shortTitleUz", "shortTitleEn", "shortTextRu", "shortTextUz", "shortTextEn", "fullTitleRu", "fullTitleUz", "fullTitleEn", "createdAt", "updatedAt") VALUES ('cmrq0anzm0027wrk1w2p7ig1l', 'google-scholar-h-index', 'h-индекс в Google Scholar', 'Google Scholar’dagi h-indeks', 'h-index in Google Scholar', 'В Google Scholar h-индекс автора рассчитывается автоматически на основе его публикаций и количества цитирований. Платформа также показывает общее число цитат и i10-index.', 'Google Scholar’da muallifning h-indeksi uning nashrlari va iqtiboslar soni asosida avtomatik hisoblanadi. Platforma umumiy iqtiboslar soni va i10-index’ni ham ko‘rsatadi.', 'In Google Scholar, an author’s h-index is calculated automatically based on publications and citation counts. The platform also shows total citations and the i10-index.', NULL, NULL, NULL, 'В Google Scholar h-индекс автора рассчитывается автоматически на основе его публикаций и количества цитирований. Платформа также показывает общее число цитат и i10-index.', 'Google Scholar’da muallifning h-indeksi uning nashrlari va iqtiboslar soni asosida avtomatik hisoblanadi. Platforma umumiy iqtiboslar soni va i10-index’ni ham ko‘rsatadi.', 'In Google Scholar, an author’s h-index is calculated automatically based on publications and citation counts. The platform also shows total citations and the i10-index.', NULL, NULL, NULL, '2026-07-18 06:49:11.41', '2026-07-18 06:49:11.41');
INSERT INTO public."UsefulPage" (id, slug, "titleRu", "titleUz", "titleEn", "cardTextRu", "cardTextUz", "cardTextEn", "shortTitleRu", "shortTitleUz", "shortTitleEn", "shortTextRu", "shortTextUz", "shortTextEn", "fullTitleRu", "fullTitleUz", "fullTitleEn", "createdAt", "updatedAt") VALUES ('cmrq0anzt002fwrk1cco2wjpl', 'scopus-h-index', 'h-индекс в Scopus', 'Scopus’dagi h-indeks', 'h-index in Scopus', 'В Scopus h-индекс рассчитывается по тем публикациям автора, которые индексируются именно в базе Scopus. Он показывает, сколько работ автора получили не менее такого же числа цитирований.', 'Scopus’da h-indeks aynan shu bazada indekslangan muallif nashrlari bo‘yicha hisoblanadi. U muallifning nechta ishi kamida shuncha marta iqtibos olganini ko‘rsatadi.', 'In Scopus, the h-index is calculated based on the author’s publications indexed specifically in the Scopus database. It shows how many works have received at least that same number of citations.', NULL, NULL, NULL, 'В Scopus h-индекс рассчитывается по тем публикациям автора, которые индексируются именно в базе Scopus. Он показывает, сколько работ автора получили не менее такого же числа цитирований.', 'Scopus’da h-indeks aynan shu bazada indekslangan muallif nashrlari bo‘yicha hisoblanadi. U muallifning nechta ishi kamida shuncha marta iqtibos olganini ko‘rsatadi.', 'In Scopus, the h-index is calculated based on the author’s publications indexed specifically in the Scopus database. It shows how many works have received at least that same number of citations.', NULL, NULL, NULL, '2026-07-18 06:49:11.417', '2026-07-18 06:49:11.417');
INSERT INTO public."UsefulPage" (id, slug, "titleRu", "titleUz", "titleEn", "cardTextRu", "cardTextUz", "cardTextEn", "shortTitleRu", "shortTitleUz", "shortTitleEn", "shortTextRu", "shortTextUz", "shortTextEn", "fullTitleRu", "fullTitleUz", "fullTitleEn", "createdAt", "updatedAt") VALUES ('cmrq0anzz002mwrk1v0f53ih9', 'difference-between-google-scholar-and-scopus-h-index', 'h-индекс в Google Scholar и в Scopus: в чём разница', 'Google Scholar va Scopus’dagi h-indeks: farqi nimada', 'h-index in Google Scholar and Scopus: what is the difference', 'h-индекс в Google Scholar и в Scopus часто не совпадает, потому что эти системы индексируют разный объём публикаций и цитирований. Google Scholar обычно показывает более широкое покрытие, а Scopus — более строгую и структурированную выборку.', 'Google Scholar va Scopus’dagi h-indeks ko‘pincha bir xil bo‘lmaydi, chunki bu tizimlar turli hajmdagi nashrlar va iqtiboslarni indekslaydi. Google Scholar odatda kengroq qamrovni, Scopus esa qat’iyroq va tartiblangan tanlovni ko‘rsatadi.', 'The h-index in Google Scholar and Scopus often differs because these systems index different volumes of publications and citations. Google Scholar usually shows broader coverage, while Scopus reflects a stricter and more structured selection.', NULL, NULL, NULL, 'h-индекс в Google Scholar и в Scopus часто не совпадает, потому что эти системы индексируют разный объём публикаций и цитирований. Google Scholar обычно показывает более широкое покрытие, а Scopus — более строгую и структурированную выборку.', 'Google Scholar va Scopus’dagi h-indeks ko‘pincha bir xil bo‘lmaydi, chunki bu tizimlar turli hajmdagi nashrlar va iqtiboslarni indekslaydi. Google Scholar odatda kengroq qamrovni, Scopus esa qat’iyroq va tartiblangan tanlovni ko‘rsatadi.', 'The h-index in Google Scholar and Scopus often differs because these systems index different volumes of publications and citations. Google Scholar usually shows broader coverage, while Scopus reflects a stricter and more structured selection.', NULL, NULL, NULL, '2026-07-18 06:49:11.423', '2026-07-18 06:49:11.423');
INSERT INTO public."UsefulPage" (id, slug, "titleRu", "titleUz", "titleEn", "cardTextRu", "cardTextUz", "cardTextEn", "shortTitleRu", "shortTitleUz", "shortTitleEn", "shortTextRu", "shortTextUz", "shortTextEn", "fullTitleRu", "fullTitleUz", "fullTitleEn", "createdAt", "updatedAt") VALUES ('cmrq0ao08002vwrk10wu96a4g', 'what-is-oak', 'Журналы, рекомендованные ВАК / ОАК', 'VAK / OAK tavsiya qilgan jurnallar', 'Journals recommended by VAK / OAK', 'Журналы ВАК / ОАК — это издания, включённые в официальный перечень, признанный для публикации основных научных результатов диссертаций. Для Узбекистана ориентироваться нужно на официальный перечень OAK.', 'VAK / OAK jurnallari — dissertatsiyalarning asosiy ilmiy natijalarini chop etish uchun tan olingan rasmiy ro‘yxatga kiritilgan nashrlardir. O‘zbekiston uchun OAKning rasmiy ro‘yxatiga tayanish kerak.', 'VAK / OAK journals are publications included in an official list recognized for publishing the main scientific results of dissertations. For Uzbekistan, one should rely on the official OAK list.', NULL, NULL, NULL, 'Журналы ВАК / ОАК — это издания, включённые в официальный перечень, признанный для публикации основных научных результатов диссертаций. Для Узбекистана ориентироваться нужно на официальный перечень OAK.', 'VAK / OAK jurnallari — dissertatsiyalarning asosiy ilmiy natijalarini chop etish uchun tan olingan rasmiy ro‘yxatga kiritilgan nashrlardir. O‘zbekiston uchun OAKning rasmiy ro‘yxatiga tayanish kerak.', 'VAK / OAK journals are publications included in an official list recognized for publishing the main scientific results of dissertations. For Uzbekistan, one should rely on the official OAK list.', NULL, NULL, NULL, '2026-07-18 06:49:11.432', '2026-07-18 06:49:11.432');
INSERT INTO public."UsefulPage" (id, slug, "titleRu", "titleUz", "titleEn", "cardTextRu", "cardTextUz", "cardTextEn", "shortTitleRu", "shortTitleUz", "shortTitleEn", "shortTextRu", "shortTextUz", "shortTextEn", "fullTitleRu", "fullTitleUz", "fullTitleEn", "createdAt", "updatedAt") VALUES ('cmrq0ao0d0032wrk1rdpgw7sl', 'publication-and-indexing-stages', 'Хронология публикации статьи в журнале Scopus', 'Scopus jurnalida maqola chop etilish xronologiyasi', 'Publication timeline of an article in a Scopus journal', 'Публикация статьи в журнале, индексируемом Scopus, — это не один шаг, а целая цепочка: подача, редакционная проверка, рецензирование, правки, принятие, техническая подготовка, онлайн-публикация и только потом — появление записи в базе.', 'Scopus indekslaydigan jurnalda maqola chop etilishi bitta bosqich emas, balki butun zanjirdir: topshirish, tahririy tekshiruv, taqriz, tuzatishlar, qabul, texnik tayyorlash, onlayn nashr va shundan keyingina bazada paydo bo‘lish.', 'Publishing an article in a Scopus-indexed journal is not a single step but a whole chain: submission, editorial screening, peer review, revisions, acceptance, technical preparation, online publication, and only then appearance in the database.', NULL, NULL, NULL, 'Публикация статьи в журнале, индексируемом Scopus, — это не один шаг, а целая цепочка: подача, редакционная проверка, рецензирование, правки, принятие, техническая подготовка, онлайн-публикация и только потом — появление записи в базе.', 'Scopus indekslaydigan jurnalda maqola chop etilishi bitta bosqich emas, balki butun zanjirdir: topshirish, tahririy tekshiruv, taqriz, tuzatishlar, qabul, texnik tayyorlash, onlayn nashr va shundan keyingina bazada paydo bo‘lish.', 'Publishing an article in a Scopus-indexed journal is not a single step but a whole chain: submission, editorial screening, peer review, revisions, acceptance, technical preparation, online publication, and only then appearance in the database.', NULL, NULL, NULL, '2026-07-18 06:49:11.437', '2026-07-18 06:49:11.437');
INSERT INTO public."UsefulPage" (id, slug, "titleRu", "titleUz", "titleEn", "cardTextRu", "cardTextUz", "cardTextEn", "shortTitleRu", "shortTitleUz", "shortTitleEn", "shortTextRu", "shortTextUz", "shortTextEn", "fullTitleRu", "fullTitleUz", "fullTitleEn", "createdAt", "updatedAt") VALUES ('cmrq0ao0k0036wrk1xvj7xujx', 'publication-frequency', 'Частота публикаций в журналах', 'Jurnallarda nashr chastotasi', 'Publication frequency in journals', 'Частота публикации показывает, как часто журнал выпускает новые номера или размещает финальные материалы: ежемесячно, ежеквартально, раз в полгода, ежегодно или по модели continuous publication.', 'Nashr chastotasi jurnal yangi sonlarni yoki yakuniy materiallarni qanchalik tez-tez chiqarishini ko‘rsatadi: har oy, har chorak, yarim yilda bir, yilda bir yoki continuous publication modeli bo‘yicha.', 'Publication frequency shows how often a journal releases new issues or posts final materials: monthly, quarterly, semiannually, annually, or under a continuous publication model.', NULL, NULL, NULL, 'Частота публикации показывает, как часто журнал выпускает новые номера или размещает финальные материалы: ежемесячно, ежеквартально, раз в полгода, ежегодно или по модели continuous publication.', 'Nashr chastotasi jurnal yangi sonlarni yoki yakuniy materiallarni qanchalik tez-tez chiqarishini ko‘rsatadi: har oy, har chorak, yarim yilda bir, yilda bir yoki continuous publication modeli bo‘yicha.', 'Publication frequency shows how often a journal releases new issues or posts final materials: monthly, quarterly, semiannually, annually, or under a continuous publication model.', NULL, NULL, NULL, '2026-07-18 06:49:11.444', '2026-07-18 06:49:11.444');
INSERT INTO public."UsefulPage" (id, slug, "titleRu", "titleUz", "titleEn", "cardTextRu", "cardTextUz", "cardTextEn", "shortTitleRu", "shortTitleUz", "shortTitleEn", "shortTextRu", "shortTextUz", "shortTextEn", "fullTitleRu", "fullTitleUz", "fullTitleEn", "createdAt", "updatedAt") VALUES ('cmrq0ao0o003ewrk183wts5mq', 'what-is-source-id', 'Что такое Source ID в Scopus', 'Scopus’da Source ID nima', 'What is Source ID in Scopus', 'Source ID — это внутренний идентификатор журнала или другого источника в системе Scopus. Он помогает точно различать источники и связывать данные без путаницы в названиях.', 'Source ID — Scopus tizimidagi jurnal yoki boshqa manbaning ichki identifikatori. U manbalarni aniq farqlash va nomlardagi chalkashliksiz ma’lumotlarni bog‘lashga yordam beradi.', 'Source ID is an internal identifier of a journal or another source in the Scopus system. It helps accurately distinguish sources and connect data without confusion in titles.', NULL, NULL, NULL, 'Source ID — это внутренний идентификатор журнала или другого источника в системе Scopus. Он помогает точно различать источники и связывать данные без путаницы в названиях.', 'Source ID — Scopus tizimidagi jurnal yoki boshqa manbaning ichki identifikatori. U manbalarni aniq farqlash va nomlardagi chalkashliksiz ma’lumotlarni bog‘lashga yordam beradi.', 'Source ID is an internal identifier of a journal or another source in the Scopus system. It helps accurately distinguish sources and connect data without confusion in titles.', NULL, NULL, NULL, '2026-07-18 06:49:11.448', '2026-07-18 06:49:11.448');
INSERT INTO public."UsefulPage" (id, slug, "titleRu", "titleUz", "titleEn", "cardTextRu", "cardTextUz", "cardTextEn", "shortTitleRu", "shortTitleUz", "shortTitleEn", "shortTextRu", "shortTextUz", "shortTextEn", "fullTitleRu", "fullTitleUz", "fullTitleEn", "createdAt", "updatedAt") VALUES ('cmrq0ao0t003kwrk1ubgm2967', 'internal-and-external-review', 'Внутренние и внешние рецензии статьи', 'Maqolaning ichki va tashqi taqrizlari', 'Internal and external review of an article', 'В публикационном процессе обычно есть два уровня оценки статьи: внутренняя редакционная проверка и внешнее научное рецензирование. Сначала статью оценивает редакция, затем — при необходимости — независимые специалисты по теме.', 'Nashr jarayonida odatda maqolani baholashning ikki darajasi bo‘ladi: ichki tahririy tekshiruv va tashqi ilmiy taqriz. Avval maqolani tahririyat ko‘radi, keyin zarur bo‘lsa mavzu bo‘yicha mustaqil mutaxassislar baholaydi.', 'In the publication process there are usually two levels of evaluation: internal editorial screening and external scholarly peer review. First the article is assessed by the editorial office, then—if needed—by independent subject experts.', NULL, NULL, NULL, 'В публикационном процессе обычно есть два уровня оценки статьи: внутренняя редакционная проверка и внешнее научное рецензирование. Сначала статью оценивает редакция, затем — при необходимости — независимые специалисты по теме.', 'Nashr jarayonida odatda maqolani baholashning ikki darajasi bo‘ladi: ichki tahririy tekshiruv va tashqi ilmiy taqriz. Avval maqolani tahririyat ko‘radi, keyin zarur bo‘lsa mavzu bo‘yicha mustaqil mutaxassislar baholaydi.', 'In the publication process there are usually two levels of evaluation: internal editorial screening and external scholarly peer review. First the article is assessed by the editorial office, then—if needed—by independent subject experts.', NULL, NULL, NULL, '2026-07-18 06:49:11.453', '2026-07-18 06:49:11.453');
INSERT INTO public."UsefulPage" (id, slug, "titleRu", "titleUz", "titleEn", "cardTextRu", "cardTextUz", "cardTextEn", "shortTitleRu", "shortTitleUz", "shortTitleEn", "shortTextRu", "shortTextUz", "shortTextEn", "fullTitleRu", "fullTitleUz", "fullTitleEn", "createdAt", "updatedAt") VALUES ('cmrq0ao10003twrk12ulf4306', 'what-is-antiplagiarism', 'Антиплагиат в статьях', 'Maqolalardagi antiplagiat', 'Antiplagiarism in articles', 'Проверка на заимствования — важная часть публикационного процесса, но её нельзя сводить к одному «безопасному проценту». Редакция оценивает не только объём совпадений, но и их характер, контекст и место в тексте.', 'O‘zlashtirishlarni tekshirish nashr jarayonining muhim qismi, ammo uni bitta «xavfsiz foiz»ga keltirib bo‘lmaydi. Tahririyat nafaqat mos tushgan hajmni, balki ularning turi, konteksti va matndagi o‘rnini ham baholaydi.', 'Similarity checking is an important part of the publication process, but it cannot be reduced to a single “safe percentage.” Editors evaluate not only the volume of overlap but also its nature, context, and location in the text.', NULL, NULL, NULL, 'Проверка на заимствования — важная часть публикационного процесса, но её нельзя сводить к одному «безопасному проценту». Редакция оценивает не только объём совпадений, но и их характер, контекст и место в тексте.', 'O‘zlashtirishlarni tekshirish nashr jarayonining muhim qismi, ammo uni bitta «xavfsiz foiz»ga keltirib bo‘lmaydi. Tahririyat nafaqat mos tushgan hajmni, balki ularning turi, konteksti va matndagi o‘rnini ham baholaydi.', 'Similarity checking is an important part of the publication process, but it cannot be reduced to a single “safe percentage.” Editors evaluate not only the volume of overlap but also its nature, context, and location in the text.', NULL, NULL, NULL, '2026-07-18 06:49:11.46', '2026-07-18 06:49:11.46');
INSERT INTO public."UsefulPage" (id, slug, "titleRu", "titleUz", "titleEn", "cardTextRu", "cardTextUz", "cardTextEn", "shortTitleRu", "shortTitleUz", "shortTitleEn", "shortTextRu", "shortTextUz", "shortTextEn", "fullTitleRu", "fullTitleUz", "fullTitleEn", "createdAt", "updatedAt") VALUES ('cmrq0ao150041wrk1nph1ubge', 'ai-in-scientific-writing', 'Использование ИИ в научных статьях', 'Ilmiy maqolalarda SI’dan foydalanish', 'Using AI in scientific articles', 'ИИ можно использовать как вспомогательный инструмент, но только прозрачно и ответственно. Искусственный интеллект не может быть автором статьи, а вся ответственность за текст всегда остаётся за человеком.', 'Sun’iy intellektdan yordamchi vosita sifatida foydalanish mumkin, ammo faqat shaffof va mas’uliyatli tarzda. Sun’iy intellekt maqola muallifi bo‘la olmaydi, matn uchun barcha javobgarlik esa doimo insonga tegishli bo‘ladi.', 'AI may be used as a supporting tool, but only transparently and responsibly. Artificial intelligence cannot be the author of an article, and all responsibility for the text always remains with a human.', NULL, NULL, NULL, 'ИИ можно использовать как вспомогательный инструмент, но только прозрачно и ответственно. Искусственный интеллект не может быть автором статьи, а вся ответственность за текст всегда остаётся за человеком.', 'Sun’iy intellektdan yordamchi vosita sifatida foydalanish mumkin, ammo faqat shaffof va mas’uliyatli tarzda. Sun’iy intellekt maqola muallifi bo‘la olmaydi, matn uchun barcha javobgarlik esa doimo insonga tegishli bo‘ladi.', 'AI may be used as a supporting tool, but only transparently and responsibly. Artificial intelligence cannot be the author of an article, and all responsibility for the text always remains with a human.', NULL, NULL, NULL, '2026-07-18 06:49:11.465', '2026-07-18 06:49:11.465');
INSERT INTO public."UsefulPage" (id, slug, "titleRu", "titleUz", "titleEn", "cardTextRu", "cardTextUz", "cardTextEn", "shortTitleRu", "shortTitleUz", "shortTitleEn", "shortTextRu", "shortTextUz", "shortTextEn", "fullTitleRu", "fullTitleUz", "fullTitleEn", "createdAt", "updatedAt") VALUES ('cmrq0ao1a0048wrk1oher4nyn', 'pre-publication-and-online-first', 'Предварительная публикация статьи на сайте журнала', 'Jurnal saytida maqolaning dastlabki e’loni', 'Preliminary publication of an article on the journal website', 'Статья может появиться на сайте журнала ещё до выхода окончательного номера. Такие версии часто называют Article in Press, journal pre-proof или online first.', 'Maqola jurnal saytida yakuniy son chiqishidan oldin ham paydo bo‘lishi mumkin. Bunday versiyalar ko‘pincha Article in Press, journal pre-proof yoki online first deb ataladi.', 'An article may appear on a journal website before the final issue is released. Such versions are often called Article in Press, journal pre-proof, or online first.', NULL, NULL, NULL, 'Статья может появиться на сайте журнала ещё до выхода окончательного номера. Такие версии часто называют Article in Press, journal pre-proof или online first.', 'Maqola jurnal saytida yakuniy son chiqishidan oldin ham paydo bo‘lishi mumkin. Bunday versiyalar ko‘pincha Article in Press, journal pre-proof yoki online first deb ataladi.', 'An article may appear on a journal website before the final issue is released. Such versions are often called Article in Press, journal pre-proof, or online first.', NULL, NULL, NULL, '2026-07-18 06:49:11.47', '2026-07-18 06:49:11.47');
INSERT INTO public."UsefulPage" (id, slug, "titleRu", "titleUz", "titleEn", "cardTextRu", "cardTextUz", "cardTextEn", "shortTitleRu", "shortTitleUz", "shortTitleEn", "shortTextRu", "shortTextUz", "shortTextEn", "fullTitleRu", "fullTitleUz", "fullTitleEn", "createdAt", "updatedAt") VALUES ('cmrq0ao1h004fwrk1mqaq7g06', 'online-publication-and-issue-release', 'Онлайн-публикация и выход номера — не одно и то же', 'Onlayn nashr va son chiqishi — bir xil emas', 'Online publication and issue release are not the same thing', 'Статья может появиться на сайте журнала раньше, чем выйдет сам номер, том или сборник. Онлайн-публикация не всегда означает, что выпуск уже завершён.', 'Maqola jurnal saytida son, tom yoki to‘plam chiqishidan oldinroq paydo bo‘lishi mumkin. Onlayn nashr har doim ham butun son tayyor bo‘lganini anglatmaydi.', 'An article may appear on the journal website before the issue, volume, or collection itself is released. Online publication does not always mean that the issue is already complete.', NULL, NULL, NULL, 'Статья может появиться на сайте журнала раньше, чем выйдет сам номер, том или сборник. Онлайн-публикация не всегда означает, что выпуск уже завершён.', 'Maqola jurnal saytida son, tom yoki to‘plam chiqishidan oldinroq paydo bo‘lishi mumkin. Onlayn nashr har doim ham butun son tayyor bo‘lganini anglatmaydi.', 'An article may appear on the journal website before the issue, volume, or collection itself is released. Online publication does not always mean that the issue is already complete.', NULL, NULL, NULL, '2026-07-18 06:49:11.477', '2026-07-18 06:49:11.477');
INSERT INTO public."UsefulPage" (id, slug, "titleRu", "titleUz", "titleEn", "cardTextRu", "cardTextUz", "cardTextEn", "shortTitleRu", "shortTitleUz", "shortTitleEn", "shortTextRu", "shortTextUz", "shortTextEn", "fullTitleRu", "fullTitleUz", "fullTitleEn", "createdAt", "updatedAt") VALUES ('cmrq0ao1n004mwrk1ly2dghhu', 'article-versions', 'Типы статьи: публикационные версии', 'Maqolaning nashr versiyalari', 'Publication versions of an article', 'Одна и та же научная работа может существовать в нескольких версиях: от авторской рукописи до окончательной опубликованной статьи. Это важно для понимания статуса текста, цитирования и правил распространения.', 'Bir xil ilmiy ish bir nechta versiyada mavjud bo‘lishi mumkin: muallif qo‘lyozmasidan tortib yakuniy chop etilgan maqolagacha. Bu matn maqomini, iqtibos keltirishni va tarqatish qoidalarini tushunish uchun muhim.', 'The same scholarly work may exist in several versions: from the author’s manuscript to the final published article. This is important for understanding the text’s status, citation, and sharing rules.', NULL, NULL, NULL, 'Одна и та же научная работа может существовать в нескольких версиях: от авторской рукописи до окончательной опубликованной статьи. Это важно для понимания статуса текста, цитирования и правил распространения.', 'Bir xil ilmiy ish bir nechta versiyada mavjud bo‘lishi mumkin: muallif qo‘lyozmasidan tortib yakuniy chop etilgan maqolagacha. Bu matn maqomini, iqtibos keltirishni va tarqatish qoidalarini tushunish uchun muhim.', 'The same scholarly work may exist in several versions: from the author’s manuscript to the final published article. This is important for understanding the text’s status, citation, and sharing rules.', NULL, NULL, NULL, '2026-07-18 06:49:11.483', '2026-07-18 06:49:11.483');
INSERT INTO public."UsefulPage" (id, slug, "titleRu", "titleUz", "titleEn", "cardTextRu", "cardTextUz", "cardTextEn", "shortTitleRu", "shortTitleUz", "shortTitleEn", "shortTextRu", "shortTextUz", "shortTextEn", "fullTitleRu", "fullTitleUz", "fullTitleEn", "createdAt", "updatedAt") VALUES ('cmrq0ao1r004swrk1ba924a71', 'scopus-document-types', 'Типы документов в Scopus', 'Scopus’dagi hujjat turlari', 'Document types in Scopus', 'Scopus делит материалы не только на статьи, но и на разные типы документов: article, review, conference paper, editorial, letter, note и другие. Тип документа влияет на то, как публикация отображается и интерпретируется в базе.', 'Scopus materiallarni faqat maqola sifatida emas, balki turli hujjat turlariga ajratadi: article, review, conference paper, editorial, letter, note va boshqalar. Hujjat turi nashrning bazada qanday ko‘rinishi va talqin qilinishiga ta’sir qiladi.', 'Scopus classifies materials not only as articles but into different document types: article, review, conference paper, editorial, letter, note, and others. The document type affects how a publication appears and is interpreted in the database.', NULL, NULL, NULL, 'Scopus делит материалы не только на статьи, но и на разные типы документов: article, review, conference paper, editorial, letter, note и другие. Тип документа влияет на то, как публикация отображается и интерпретируется в базе.', 'Scopus materiallarni faqat maqola sifatida emas, balki turli hujjat turlariga ajratadi: article, review, conference paper, editorial, letter, note va boshqalar. Hujjat turi nashrning bazada qanday ko‘rinishi va talqin qilinishiga ta’sir qiladi.', 'Scopus classifies materials not only as articles but into different document types: article, review, conference paper, editorial, letter, note, and others. The document type affects how a publication appears and is interpreted in the database.', NULL, NULL, NULL, '2026-07-18 06:49:11.487', '2026-07-18 06:49:11.487');
INSERT INTO public."UsefulPage" (id, slug, "titleRu", "titleUz", "titleEn", "cardTextRu", "cardTextUz", "cardTextEn", "shortTitleRu", "shortTitleUz", "shortTitleEn", "shortTextRu", "shortTextUz", "shortTextEn", "fullTitleRu", "fullTitleUz", "fullTitleEn", "createdAt", "updatedAt") VALUES ('cmrq0ao1x004zwrk1dx0z6bh9', 'publication-vs-indexing-in-scopus', 'Публикация статьи и индексация в Scopus', 'Maqola nashri va Scopus’dagi indeksatsiya', 'Article publication and indexing in Scopus', 'Публикация статьи и её индексация в Scopus — это разные процессы. Статья сначала публикуется журналом, а затем её данные передаются и обрабатываются в базе.', 'Maqolaning chop etilishi va uning Scopus’da indekslanishi ikki xil jarayondir. Avval maqolani jurnal chop etadi, keyin uning ma’lumotlari bazaga uzatiladi va qayta ishlanadi.', 'Article publication and its indexing in Scopus are different processes. The article is first published by the journal, and only then its data are transferred to and processed in the database.', NULL, NULL, NULL, 'Публикация статьи и её индексация в Scopus — это разные процессы. Статья сначала публикуется журналом, а затем её данные передаются и обрабатываются в базе.', 'Maqolaning chop etilishi va uning Scopus’da indekslanishi ikki xil jarayondir. Avval maqolani jurnal chop etadi, keyin uning ma’lumotlari bazaga uzatiladi va qayta ishlanadi.', 'Article publication and its indexing in Scopus are different processes. The article is first published by the journal, and only then its data are transferred to and processed in the database.', NULL, NULL, NULL, '2026-07-18 06:49:11.493', '2026-07-18 06:49:11.493');
INSERT INTO public."UsefulPage" (id, slug, "titleRu", "titleUz", "titleEn", "cardTextRu", "cardTextUz", "cardTextEn", "shortTitleRu", "shortTitleUz", "shortTitleEn", "shortTextRu", "shortTextUz", "shortTextEn", "fullTitleRu", "fullTitleUz", "fullTitleEn", "createdAt", "updatedAt") VALUES ('cmrq0ao220056wrk15gnfsd5o', 'how-to-check-article-indexing-in-scopus', 'Как проверить индексацию статьи в Scopus', 'Maqolaning Scopus’da indekslanganini qanday tekshirish kerak', 'How to check article indexing in Scopus', 'Проверять индексацию статьи в Scopus лучше сразу несколькими способами: по DOI, точному названию статьи, профилю автора и самому журналу.', 'Maqolaning Scopus’da indekslanganini bir nechta usul bilan tekshirgan ma’qul: DOI, maqolaning aniq nomi, muallif profili va jurnalning o‘zi orqali.', 'It is better to check whether an article is indexed in Scopus using several methods at once: by DOI, exact article title, author profile, and the journal itself.', NULL, NULL, NULL, 'Проверять индексацию статьи в Scopus лучше сразу несколькими способами: по DOI, точному названию статьи, профилю автора и самому журналу.', 'Maqolaning Scopus’da indekslanganini bir nechta usul bilan tekshirgan ma’qul: DOI, maqolaning aniq nomi, muallif profili va jurnalning o‘zi orqali.', 'It is better to check whether an article is indexed in Scopus using several methods at once: by DOI, exact article title, author profile, and the journal itself.', NULL, NULL, NULL, '2026-07-18 06:49:11.498', '2026-07-18 06:49:11.498');
INSERT INTO public."UsefulPage" (id, slug, "titleRu", "titleUz", "titleEn", "cardTextRu", "cardTextUz", "cardTextEn", "shortTitleRu", "shortTitleUz", "shortTitleEn", "shortTextRu", "shortTextUz", "shortTextEn", "fullTitleRu", "fullTitleUz", "fullTitleEn", "createdAt", "updatedAt") VALUES ('cmrq0ao26005dwrk17l9ye0c9', 'article-acceptance-stages', 'Этапы принятия статьи в журналах Scopus', 'Scopus jurnallarida maqolani qabul qilish bosqichlari', 'Stages of article acceptance in Scopus journals', 'Статья в журнале, индексируемом Scopus, обычно проходит несколько стадий: редакционная проверка, рецензирование, возможные правки, принятие, техническая подготовка и публикация. Само принятие статьи — важный этап, но не финал всего процесса.', 'Scopus indekslaydigan jurnaldagi maqola odatda bir necha bosqichdan o‘tadi: tahririy tekshiruv, taqriz, ehtimoliy tuzatishlar, qabul, texnik tayyorlash va nashr. Maqolaning qabul qilinishi muhim bosqich, lekin butun jarayonning yakuni emas.', 'An article in a Scopus-indexed journal usually goes through several stages: editorial screening, peer review, possible revisions, acceptance, technical preparation, and publication. Acceptance itself is an important stage, but not the end of the whole process.', NULL, NULL, NULL, 'Статья в журнале, индексируемом Scopus, обычно проходит несколько стадий: редакционная проверка, рецензирование, возможные правки, принятие, техническая подготовка и публикация. Само принятие статьи — важный этап, но не финал всего процесса.', 'Scopus indekslaydigan jurnaldagi maqola odatda bir necha bosqichdan o‘tadi: tahririy tekshiruv, taqriz, ehtimoliy tuzatishlar, qabul, texnik tayyorlash va nashr. Maqolaning qabul qilinishi muhim bosqich, lekin butun jarayonning yakuni emas.', 'An article in a Scopus-indexed journal usually goes through several stages: editorial screening, peer review, possible revisions, acceptance, technical preparation, and publication. Acceptance itself is an important stage, but not the end of the whole process.', NULL, NULL, NULL, '2026-07-18 06:49:11.502', '2026-07-18 06:49:11.502');
INSERT INTO public."UsefulPage" (id, slug, "titleRu", "titleUz", "titleEn", "cardTextRu", "cardTextUz", "cardTextEn", "shortTitleRu", "shortTitleUz", "shortTitleEn", "shortTextRu", "shortTextUz", "shortTextEn", "fullTitleRu", "fullTitleUz", "fullTitleEn", "createdAt", "updatedAt") VALUES ('cmrq0ao2b005iwrk1ds97t2ds', 'myth-of-5-year-indexing', 'Сроки индексации в Scopus и миф про удаление через 5 лет', 'Scopus’dagi indeksatsiya muddatlari va 5 yildan keyin o‘chirish haqidagi mif', 'Scopus indexing timelines and the myth of removal after 5 years', 'Единого точного срока индексации статьи в Scopus нет. Появление записи зависит от издателя, качества метаданных и внутренней обработки. Утверждение, что индексация «автоматически удаляется через 5 лет», официальными источниками не подтверждается.', 'Scopus’da maqolaning indekslanishi uchun yagona aniq muddat yo‘q. Yozuvning paydo bo‘lishi nashriyotga, metadata sifatiga va ichki qayta ishlashga bog‘liq. Indeksatsiya «5 yildan keyin avtomatik o‘chadi» degan gap rasmiy manbalar bilan tasdiqlanmaydi.', 'There is no single exact time frame for indexing an article in Scopus. The appearance of a record depends on the publisher, metadata quality, and internal processing. The claim that indexing is “automatically removed after 5 years” is not confirmed by official sources.', NULL, NULL, NULL, 'Единого точного срока индексации статьи в Scopus нет. Появление записи зависит от издателя, качества метаданных и внутренней обработки. Утверждение, что индексация «автоматически удаляется через 5 лет», официальными источниками не подтверждается.', 'Scopus’da maqolaning indekslanishi uchun yagona aniq muddat yo‘q. Yozuvning paydo bo‘lishi nashriyotga, metadata sifatiga va ichki qayta ishlashga bog‘liq. Indeksatsiya «5 yildan keyin avtomatik o‘chadi» degan gap rasmiy manbalar bilan tasdiqlanmaydi.', 'There is no single exact time frame for indexing an article in Scopus. The appearance of a record depends on the publisher, metadata quality, and internal processing. The claim that indexing is “automatically removed after 5 years” is not confirmed by official sources.', NULL, NULL, NULL, '2026-07-18 06:49:11.507', '2026-07-18 06:49:11.507');
INSERT INTO public."UsefulPage" (id, slug, "titleRu", "titleUz", "titleEn", "cardTextRu", "cardTextUz", "cardTextEn", "shortTitleRu", "shortTitleUz", "shortTitleEn", "shortTextRu", "shortTextUz", "shortTextEn", "fullTitleRu", "fullTitleUz", "fullTitleEn", "createdAt", "updatedAt") VALUES ('cmrq0ao2g005qwrk1749quff4', 'what-is-scientific-article', 'Что такое научная статья', 'Ilmiy maqola nima', 'What is a scientific article', 'Научная статья — это структурированный текст, в котором автор представляет результаты исследования, анализа, наблюдений или эксперимента в академической форме.', 'Ilmiy maqola — muallif tadqiqot, tahlil, kuzatish yoki eksperiment natijalarini akademik shaklda taqdim etadigan tuzilgan matndir.', 'A scientific article is a structured text in which an author presents the results of research, analysis, observation, or experiment in an academic form.', NULL, NULL, NULL, 'Научная статья — это структурированный текст, в котором автор представляет результаты исследования, анализа, наблюдений или эксперимента в академической форме.', 'Ilmiy maqola — muallif tadqiqot, tahlil, kuzatish yoki eksperiment natijalarini akademik shaklda taqdim etadigan tuzilgan matndir.', 'A scientific article is a structured text in which an author presents the results of research, analysis, observation, or experiment in an academic form.', NULL, NULL, NULL, '2026-07-18 06:49:11.512', '2026-07-18 06:49:11.512');
INSERT INTO public."UsefulPage" (id, slug, "titleRu", "titleUz", "titleEn", "cardTextRu", "cardTextUz", "cardTextEn", "shortTitleRu", "shortTitleUz", "shortTitleEn", "shortTextRu", "shortTextUz", "shortTextEn", "fullTitleRu", "fullTitleUz", "fullTitleEn", "createdAt", "updatedAt") VALUES ('cmrq0ao2l005wwrk1q3x9atji', 'what-is-journal-publication', 'Что такое публикация в журнале', 'Jurnalda nashr nima', 'What is publication in a journal', 'Публикация в журнале — это процесс превращения рукописи автора в официальную научную публикацию после редакционной обработки и, как правило, рецензирования.', 'Jurnalda nashr — bu muallif qo‘lyozmasining tahririy ishlov va odatda taqrizdan so‘ng rasmiy ilmiy nashrga aylanish jarayonidir.', 'Publication in a journal is the process of turning an author’s manuscript into an official scholarly publication after editorial processing and, as a rule, peer review.', NULL, NULL, NULL, 'Публикация в журнале — это процесс превращения рукописи автора в официальную научную публикацию после редакционной обработки и, как правило, рецензирования.', 'Jurnalda nashr — bu muallif qo‘lyozmasining tahririy ishlov va odatda taqrizdan so‘ng rasmiy ilmiy nashrga aylanish jarayonidir.', 'Publication in a journal is the process of turning an author’s manuscript into an official scholarly publication after editorial processing and, as a rule, peer review.', NULL, NULL, NULL, '2026-07-18 06:49:11.517', '2026-07-18 06:49:11.517');
INSERT INTO public."UsefulPage" (id, slug, "titleRu", "titleUz", "titleEn", "cardTextRu", "cardTextUz", "cardTextEn", "shortTitleRu", "shortTitleUz", "shortTitleEn", "shortTextRu", "shortTextUz", "shortTextEn", "fullTitleRu", "fullTitleUz", "fullTitleEn", "createdAt", "updatedAt") VALUES ('cmrq0ao2s0063wrk1g755l3w4', 'what-is-scientific-journal', 'Что такое научный журнал для статей', 'Maqolalar uchun ilmiy jurnal nima', 'What is a scientific journal for articles', 'Научный журнал — это периодическое издание, в котором публикуются исследовательские материалы, оформленные по академическим стандартам и проходящие редакционную процедуру.', 'Ilmiy jurnal — akademik standartlar asosida rasmiylashtirilgan va tahririy jarayondan o‘tadigan tadqiqot materiallari chop etiladigan davriy nashrdir.', 'A scientific journal is a periodical in which research materials are published according to academic standards and undergo an editorial process.', NULL, NULL, NULL, 'Научный журнал — это периодическое издание, в котором публикуются исследовательские материалы, оформленные по академическим стандартам и проходящие редакционную процедуру.', 'Ilmiy jurnal — akademik standartlar asosida rasmiylashtirilgan va tahririy jarayondan o‘tadigan tadqiqot materiallari chop etiladigan davriy nashrdir.', 'A scientific journal is a periodical in which research materials are published according to academic standards and undergo an editorial process.', NULL, NULL, NULL, '2026-07-18 06:49:11.524', '2026-07-18 06:49:11.524');
INSERT INTO public."UsefulPage" (id, slug, "titleRu", "titleUz", "titleEn", "cardTextRu", "cardTextUz", "cardTextEn", "shortTitleRu", "shortTitleUz", "shortTitleEn", "shortTextRu", "shortTextUz", "shortTextEn", "fullTitleRu", "fullTitleUz", "fullTitleEn", "createdAt", "updatedAt") VALUES ('cmrq0ao2z006awrk106wal4qw', 'difference-between-thesis-and-article', 'Разница между научным тезисом и научной статьёй', 'Ilmiy tezis va ilmiy maqola o‘rtasidagi farq', 'Difference between a scientific thesis abstract and a scientific article', 'Научный тезис и научная статья — это не одно и то же, хотя оба формата относятся к академической публикации. Разница между ними прежде всего в объёме, глубине изложения и цели.', 'Ilmiy tezis va ilmiy maqola bir xil narsa emas, garchi ikkala format ham akademik nashrga tegishli bo‘lsa-da. Ular orasidagi farq, avvalo, hajm, bayon chuqurligi va maqsadda.', 'A scientific thesis abstract and a scientific article are not the same thing, although both belong to academic publishing. The difference lies primarily in volume, depth of presentation, and purpose.', NULL, NULL, NULL, 'Тезисы — это короткое изложение исследования. Научная статья — это полноценный научный текст с методами, результатами, обсуждением и выводами.', 'Tezislar — tadqiqotning qisqacha bayonidir. Ilmiy maqola esa metodlar, natijalar, muhokama va xulosalardan iborat to‘laqonli ilmiy matndir.', 'Theses/abstracts are a short presentation of research. A scientific article is a full scholarly text with methods, results, discussion, and conclusions.', NULL, NULL, NULL, '2026-07-18 06:49:11.531', '2026-07-18 06:49:11.531');
INSERT INTO public."UsefulPage" (id, slug, "titleRu", "titleUz", "titleEn", "cardTextRu", "cardTextUz", "cardTextEn", "shortTitleRu", "shortTitleUz", "shortTitleEn", "shortTextRu", "shortTextUz", "shortTextEn", "fullTitleRu", "fullTitleUz", "fullTitleEn", "createdAt", "updatedAt") VALUES ('cmrq0ao34006kwrk1c4xy1ot8', 'what-is-issn', 'Что такое ISSN', 'ISSN nima', 'What is ISSN', 'ISSN — это международный номер сериального издания. Он нужен для точной идентификации журнала или другого продолжающегося ресурса.', 'ISSN — bu davriy nashrning xalqaro raqami. U jurnal yoki boshqa davomli resursni aniq identifikatsiya qilish uchun kerak.', 'ISSN is the international number of a serial publication. It is used for the accurate identification of a journal or another continuing resource.', NULL, NULL, NULL, 'ISSN — это международный номер сериального издания. Он нужен для точной идентификации журнала или другого продолжающегося ресурса.', 'ISSN — bu davriy nashrning xalqaro raqami. U jurnal yoki boshqa davomli resursni aniq identifikatsiya qilish uchun kerak.', 'ISSN is the international number of a serial publication. It is used for the accurate identification of a journal or another continuing resource.', NULL, NULL, NULL, '2026-07-18 06:49:11.536', '2026-07-18 06:49:11.536');
INSERT INTO public."UsefulPage" (id, slug, "titleRu", "titleUz", "titleEn", "cardTextRu", "cardTextUz", "cardTextEn", "shortTitleRu", "shortTitleUz", "shortTitleEn", "shortTextRu", "shortTextUz", "shortTextEn", "fullTitleRu", "fullTitleUz", "fullTitleEn", "createdAt", "updatedAt") VALUES ('cmrq0ao39006uwrk119hwt0ue', 'how-to-determine-journal-country', 'Как определить страну журнала', 'Jurnal mamlakatini qanday aniqlash kerak', 'How to determine a journal’s country', 'Страну журнала не стоит определять по названию, языку сайта или ISSN. Надёжнее смотреть на данные текущего издателя и официальные библиографические записи.', 'Jurnal mamlakatini nomi, sayt tili yoki ISSN orqali aniqlash to‘g‘ri emas. Amaldagi nashriyot ma’lumotlari va rasmiy bibliografik yozuvlarga qarash ishonchliroq.', 'A journal’s country should not be determined by its name, website language, or ISSN. It is more reliable to look at the current publisher’s data and official bibliographic records.', NULL, NULL, NULL, 'Страну журнала не стоит определять по названию, языку сайта или ISSN. Надёжнее смотреть на данные текущего издателя и официальные библиографические записи.', 'Jurnal mamlakatini nomi, sayt tili yoki ISSN orqali aniqlash to‘g‘ri emas. Amaldagi nashriyot ma’lumotlari va rasmiy bibliografik yozuvlarga qarash ishonchliroq.', 'A journal’s country should not be determined by its name, website language, or ISSN. It is more reliable to look at the current publisher’s data and official bibliographic records.', NULL, NULL, NULL, '2026-07-18 06:49:11.541', '2026-07-18 06:49:11.541');
